#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int supervisors[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &supervisors[i]);
    }
    int subordinates[n];
    for (int i = 0; i < n; i++) {
        subordinates[i] = 0;
    }
    for (int i = 0; i < n; i++) {
        if (supervisors[i] != 0) {
            subordinates[supervisors[i] - 1]++;
        }
    }
    for (int i = 0; i < n; i++) {
        printf("%d\n", subordinates[i]);
    }
    return 0;
}

