code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let supervisors = [];
let subordinates = [];
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        supervisors.push(parseInt(input));
        if (supervisors.length === n) {
            subordinates = new Array(n).fill(0);
            for (let i = 0; i < n; i++) {
                if (supervisors[i] !== 0) {
                    subordinates[supervisors[i] - 1]++;
                }
            }
            for (let i = 0; i < n; i++) {
                console.log(subordinates[i]);
            }
            rl.close();
        }
    }
});
